<template><PageHeader title="表情包管理"><el-button type="primary" @click="add">发布表情包</el-button></PageHeader><div class="panel"><el-table :data="rows"><el-table-column prop="version" label="版本"/><el-table-column prop="url" label="地址"/><el-table-column prop="status" label="状态"/></el-table></div></template><script setup lang="ts">import{onMounted,ref}from'vue';import PageHeader from'@/components/PageHeader.vue';import{adminApi}from'@/services/admin-api';const rows=ref<any[]>([]);async function load(){rows.value=await adminApi.expressions()}async function add(){await adminApi.addExpression({version:`2.0.${Date.now()}`,url:'https://cdn.example.com/expression.zip'});await load()}onMounted(load);</script>
